struct VirtIOInputInner {
    virtio_input: VirtIOInput<'static, VirtioHal>,
    events: VecDeque<u64>,
}

struct VirtIOInputWrapper {
    inner: UPIntrFreeCell<VirtIOInputInner>,
    condvar: Condvar,
}

/// Input device interface.
pub trait InputDevice: Send + Sync + Any {
    /// Read a single input event.
    fn read_event(&self) -> u64;
    /// Handle device interrupt.
    fn handle_irq(&self);
    /// Whether the device event queue is empty.
    fn is_empty(&self) -> bool;
}

lazy_static::lazy_static!(
    /// Global keyboard input device.
    pub static ref KEYBOARD_DEVICE: Arc<dyn InputDevice> =
        Arc::new(VirtIOInputWrapper::new(input_base(DeviceKind::InputKeyboard)));
    /// Global mouse input device.
    pub static ref MOUSE_DEVICE: Arc<dyn InputDevice> =
        Arc::new(VirtIOInputWrapper::new(input_base(DeviceKind::InputMouse)));
);

fn input_base(kind: DeviceKind) -> usize {
    arch::platform_config()
        .device(kind)
        .and_then(|device| device.mmio_base())
        .expect("VirtIO input MMIO base missing from platform config")
}

impl VirtIOInputWrapper {
    pub fn new(addr: usize) -> Self {
        let inner = VirtIOInputInner {
            virtio_input: unsafe {
                VirtIOInput::<VirtioHal>::new(&mut *(addr as *mut VirtIOHeader)).unwrap()
            },
            events: VecDeque::new(),
        };
        Self {
            inner: unsafe { UPIntrFreeCell::new(inner) },
            condvar: Condvar::new(),
        }
    }
}

impl InputDevice for VirtIOInputWrapper {
    fn is_empty(&self) -> bool {
        self.inner.exclusive_access().events.is_empty()
    }

    fn read_event(&self) -> u64 {
        loop {
            let mut inner = self.inner.exclusive_access();
            if let Some(event) = inner.events.pop_front() {
                return event;
            } else {
                let task_cx_ptr = self.condvar.wait_no_sched();
                drop(inner);
                schedule(task_cx_ptr);
            }
        }
    }

    fn handle_irq(&self) {
        let mut count = 0;
        let mut result = 0;
        self.inner.exclusive_session(|inner| {
            inner.virtio_input.ack_interrupt();
            while let Some(event) = inner.virtio_input.pop_pending_event() {
                count += 1;
                result = (event.event_type as u64) << 48
                    | (event.code as u64) << 32
                    | (event.value) as u64;
                inner.events.push_back(result);
            }
        });
        if count > 0 {
            self.condvar.signal();
        };
    }
}

//! SBI call wrappers

#![allow(unused)]

use core::arch::asm;

const SBI_SET_TIMER: usize = 0;
const SBI_CONSOLE_PUTCHAR: usize = 1;
const SBI_CONSOLE_GETCHAR: usize = 2;
const SBI_SHUTDOWN: usize = 8;

/// general sbi call
#[inline(always)]
fn sbi_call(which: usize, arg0: usize, arg1: usize, arg2: usize) -> usize {
    let mut ret;
    unsafe {
        asm!(
            "ecall",
            inlateout("x10") arg0 => ret,
            in("x11") arg1,
            in("x12") arg2,
            in("x16") 0,
            in("x17") which,
        );
    }
    ret
}

/// use sbi call to set timer
pub fn set_timer(timer: usize) {
    sbi_call(SBI_SET_TIMER, timer, 0, 0);
}

/// use sbi call to putchar in console (qemu uart handler)
pub fn console_putchar(c: usize) {
    sbi_call(SBI_CONSOLE_PUTCHAR, c, 0, 0);
}

/// use sbi call to getchar from console (qemu uart handler)
pub fn console_getchar() -> usize {
    sbi_call(SBI_CONSOLE_GETCHAR, 0, 0, 0)
}

/// use sbi call to shutdown the kernel
pub fn shutdown() -> ! {
    sbi_call(SBI_SHUTDOWN, 0, 0, 0);
    panic!("It should shutdown!");
}

//! Kernel boot sequence.
//!
//! `rust_main` is the first Rust function called from the assembly entry
//! point (`_start` in `arch/src/riscv64/entry.asm` or the LoongArch64
//! equivalent).  It initializes all kernel subsystems and enters the
//! scheduler loop.

/// The Rust entry-point of the kernel (RISC-V 64).
#[cfg(target_arch = "riscv64")]
#[no_mangle]
pub fn rust_main() -> ! {
    arch::switch_to_kernel_page_table();
    unsafe {
        core::arch::asm!(
            "or sp, sp, {virt_base}",
            virt_base = in(reg) arch::VIRT_ADDR_START
        );
    }
    let entry_high = arch::kernel_text_addr(rust_main_high as usize);
    let entry: fn() -> ! = unsafe { core::mem::transmute(entry_high) };
    entry();
}

#[cfg(target_arch = "riscv64")]
#[inline(never)]
fn rust_main_high() -> ! {
    arch::clear_bss();
    crate::logging::init();
    crate::mm::init();
    // Under the high-half kernel execution model, the legacy remap_test
    // assumptions about section-level low-half mappings do not hold.
    // Keep boot path moving and add a dedicated high-half sanity check later.
    arch::trap_init();
    arch::trap_enable_timer_interrupt();
    crate::timer::set_next_trigger();
    crate::platform::platform_init();
    #[cfg(feature = "ext4")]
    if crate::fs::mount_ext4_auto() {
        info!("[kernel] ext4 mounted as root");
        crate::fs::ensure_busybox_links();
    } else if crate::fs::mount_fat32_auto() {
        info!("[kernel] fat32 mounted as root");
    } else {
        crate::fs::mount_easyfs();
    }
    #[cfg(not(feature = "ext4"))]
    if crate::fs::mount_fat32_auto() {
        info!("[kernel] fat32 mounted as root");
    } else {
        crate::fs::mount_easyfs();
    }
    crate::fs::mount_procfs();
    crate::fs::ensure_basic_paths();
    crate::fs::list_apps();
    crate::net::init();
    crate::task::add_initproc();
    #[cfg(target_arch = "riscv64")]
    {
        // Keep polling mode as default; allow opt-in via compile-time env for perf experiments.
        let use_non_blocking = option_env!("VIRTIO_BLK_NON_BLOCKING").is_some();
        *crate::DEV_NON_BLOCKING_ACCESS.exclusive_access() = use_non_blocking;
        info!(
            "[block] virtio non-blocking mode={}",
            if use_non_blocking { "on" } else { "off" }
        );
    }
    crate::task::run_tasks();
    panic!("Unreachable in rust_main!");
}

